import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { ConfirmModalComponent } from '../../../core/components/confirm-modal/confirm-modal.component';
import { ToastService } from '../../../core/services/toast.service';
import { getSubscriptionClass } from '../../../core/utils/subscription.utils';
import { DocenteRequest, DocenteResponse } from '../../../core/models/docente.model';
import { DocenteService } from '../../../core/services/docente.service';

@Component({
  selector: 'app-docentes',
  standalone: true,
  imports: [CommonModule, FormsModule, ReactiveFormsModule, ConfirmModalComponent],
  templateUrl: './docentes.component.html',
  styleUrls: ['./docentes.component.css']
})
export class DocentesComponent implements OnInit {
  private docenteService = inject(DocenteService);
  private fb = inject(FormBuilder);
  private toastService = inject(ToastService);

  docentes: DocenteResponse[] = [];
  filteredDocentes: DocenteResponse[] = [];
  searchQuery = '';
  dateSortOrder: 'desc' | 'asc' = 'desc';
  currentPage = 1;
  readonly pageSize = 10;
  totalElements = 0;

  showCreateEditModal = false;
  isEditMode = false;
  isFormSubmitting = false;
  modalErrorMsg = '';
  showConfirmModal = false;
  confirmModalType: 'success' | 'danger' | 'info' | 'warning' = 'warning';
  confirmModalTitle = '';
  confirmModalMessage = '';
  pendingAction: (() => void) | null = null;
  selectedDocente: DocenteResponse | null = null;

  docenteForm: FormGroup = this.fb.group({
    nombres: ['', [Validators.required, Validators.minLength(2), Validators.maxLength(100)]],
    apellidos: ['', [Validators.required, Validators.minLength(2), Validators.maxLength(100)]],
    correo: ['', [Validators.required, Validators.email, Validators.maxLength(150)]],
    telefono: [''],
    password: ['', [Validators.minLength(6)]],
    estado: [true]
  });

  ngOnInit(): void { this.loadDocentes(); }

  loadDocentes(): void {
    this.docenteService.listarDocentes(this.currentPage - 1, this.pageSize, this.searchQuery).subscribe({
      next: (res) => {
        this.docentes = Array.isArray(res) ? res : (res?.content ?? []);
        this.totalElements = Array.isArray(res) ? this.docentes.length : (res?.totalElements ?? this.docentes.length);
        this.applyFilter();
      },
      error: (err) => console.error('Error al listar docentes', err)
    });
  }

  applyFilter(): void {
    this.filteredDocentes = [...this.docentes].sort((a, b) => {
      const d1 = new Date(a.fechaRegistro).getTime() || 0;
      const d2 = new Date(b.fechaRegistro).getTime() || 0;
      return this.dateSortOrder === 'asc' ? d1 - d2 : d2 - d1;
    });
  }

  onSearchChange(): void { this.currentPage = 1; this.loadDocentes(); }
  onDateSortChange(order: string): void { this.dateSortOrder = order === 'asc' ? 'asc' : 'desc'; this.applyFilter(); }
  get totalPages(): number { return Math.max(1, Math.ceil(this.totalElements / this.pageSize)); }
  get paginatedDocentes(): DocenteResponse[] { return this.filteredDocentes; }
  goToPage(page: number): void { if (page < 1 || page > this.totalPages) return; this.currentPage = page; this.loadDocentes(); }
  previousPage(): void { this.goToPage(this.currentPage - 1); }
  nextPage(): void { this.goToPage(this.currentPage + 1); }
  trackByDocenteId(_: number, docente: DocenteResponse): number { return docente.id; }

  openCreateModal(): void {
    this.isEditMode = false; this.modalErrorMsg = ''; this.selectedDocente = null;
    this.docenteForm.reset({ nombres: '', apellidos: '', correo: '', telefono: '', password: '', estado: true });
    this.showCreateEditModal = true;
  }
  openEditModal(docente: DocenteResponse): void {
    this.isEditMode = true; this.modalErrorMsg = ''; this.selectedDocente = docente;
    this.docenteForm.patchValue({ nombres: docente.nombres, apellidos: docente.apellidos, correo: docente.correo, telefono: docente.telefono, password: '', estado: docente.estado });
    this.showCreateEditModal = true;
  }
  closeCreateEditModal(): void { this.showCreateEditModal = false; this.isFormSubmitting = false; }
  toggleEstado(docente: DocenteResponse): void {
    const nuevoEstado = !docente.estado;
    this.confirmModalType = nuevoEstado ? 'success' : 'danger';
    this.confirmModalTitle = `¿${nuevoEstado ? 'Activar' : 'Desactivar'} Docente?`;
    this.confirmModalMessage = `¿Deseas ${nuevoEstado ? 'activar' : 'desactivar'} a ${docente.nombres} ${docente.apellidos}?`;
    this.pendingAction = () => this.docenteService.cambiarEstado(docente.id, nuevoEstado).subscribe({
      next: () => { docente.estado = nuevoEstado; this.toastService.success(`Docente ${nuevoEstado ? 'activado' : 'desactivado'} exitosamente.`); this.showConfirmModal = false; },
      error: (err) => { this.toastService.error(err.error?.message || 'Error al cambiar el estado del docente.'); this.showConfirmModal = false; }
    });
    this.showConfirmModal = true;
  }
  confirmAction(): void { this.pendingAction?.(); }
  onSubmit(): void {
    if (this.docenteForm.invalid) {
      this.docenteForm.markAllAsTouched();
      this.toastService.warning('Por favor completa los campos requeridos correctamente.');
      return;
    }
    const req: DocenteRequest = { nombres: this.docenteForm.value.nombres, apellidos: this.docenteForm.value.apellidos, correo: this.docenteForm.value.correo, telefono: this.docenteForm.value.telefono || '', password: this.docenteForm.value.password || undefined };
    this.isFormSubmitting = true;
    const call$ = this.isEditMode && this.selectedDocente ? this.docenteService.editarDocente(this.selectedDocente.id, req) : this.docenteService.crearDocente(req);
    call$.subscribe({
      next: () => {
        const stateChanged = this.isEditMode && this.selectedDocente && this.docenteForm.value.estado !== this.selectedDocente.estado;
        if (stateChanged && this.selectedDocente) {
          this.docenteService.cambiarEstado(this.selectedDocente.id, this.docenteForm.value.estado).subscribe({
            next: () => {
              this.loadDocentes();
              this.toastService.success('Docente y estado actualizados exitosamente.');
              this.closeCreateEditModal();
            },
            error: (err) => {
              this.isFormSubmitting = false;
              this.modalErrorMsg = err.error?.message || 'Error al actualizar el estado del docente.';
              this.toastService.error(this.modalErrorMsg, 'Error en el Servidor');
            }
          });
          return;
        }
        this.loadDocentes();
        this.toastService.success(this.isEditMode ? 'Docente actualizado exitosamente.' : 'Docente registrado exitosamente.');
        this.closeCreateEditModal();
      },
      error: (err) => { this.isFormSubmitting = false; this.modalErrorMsg = err.error?.message || 'Error al procesar la solicitud.'; this.toastService.error(this.modalErrorMsg, 'Error en el Servidor'); }
    });
  }

  getSubscriptionClass = getSubscriptionClass;
}
<div class="space-y-6 font-body">
  <div class="border border-slate-200 dark:border-slate-800 p-4 md:p-6 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex flex-col gap-4 md:flex-row md:justify-between md:items-center transition-colors duration-300">
    <div>
      <h1 class="text-xl md:text-2xl font-black text-slate-900 dark:text-white tracking-tight uppercase">Gestion de Docentes</h1>
      <p class="text-slate-500 dark:text-slate-400 text-xs mt-1">Control de docentes activos, acceso a la plataforma y estado de cuentas academicas.</p>
    </div>
    <div class="flex flex-col gap-2 md:flex-row md:gap-2 w-full md:w-auto">
      <button
        (click)="openCreateModal()"
        class="flex items-center justify-center gap-2 px-4 py-2.5 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors duration-300 rounded-none w-full md:w-auto">
        <span class="material-symbols-outlined text-sm">add</span>
        <span>Crear Docente</span>
      </button>
    </div>
  </div>

  <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] overflow-hidden transition-colors duration-300">
    <div class="p-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between transition-colors duration-300">
      <div class="relative w-full">
        <span class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400 dark:text-slate-500">
          <span class="material-symbols-outlined text-base">search</span>
        </span>
        <input
          [(ngModel)]="searchQuery"
          (input)="onSearchChange()"
          class="block w-full pl-9 pr-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary text-xs rounded-none transition-colors duration-300"
          placeholder="Buscar por nombre o correo...">
      </div>
      <div class="flex flex-col sm:flex-row gap-2 items-stretch sm:items-center">
        <select [ngModel]="dateSortOrder" (ngModelChange)="onDateSortChange($event)" class="px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-xs font-bold uppercase tracking-wider">
          <option value="desc">Fecha desc</option>
          <option value="asc">Fecha asc</option>
        </select>
        <span class="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider whitespace-nowrap">
          {{ totalElements }} docentes encontrados
        </span>
      </div>
    </div>

    <div class="md:hidden divide-y divide-slate-100 dark:divide-slate-800">
      <div *ngIf="filteredDocentes.length === 0" class="p-10 text-center text-slate-400 dark:text-slate-500">
        <span class="material-symbols-outlined text-4xl mb-2 text-slate-300 dark:text-slate-700">groups</span>
        <p class="font-medium text-xs">No se encontraron docentes registrados.</p>
      </div>

      <div *ngFor="let docente of paginatedDocentes; trackBy: trackByDocenteId" class="p-4 space-y-3 bg-white dark:bg-slate-900 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors duration-300">
        <div class="flex items-start justify-between gap-2">
          <div>
            <p class="font-bold text-slate-900 dark:text-white text-sm leading-tight">{{ docente.nombres }} {{ docente.apellidos }}</p>
            <p class="text-xs text-slate-500 dark:text-slate-400 mt-0.5 break-all">{{ docente.correo }}</p>
          </div>
          <span [ngClass]="docente.estado ? 'bg-emerald-50 text-emerald-700 border-emerald-300 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900' : 'bg-red-50 text-red-700 border-red-300 dark:bg-red-950/30 dark:text-red-400 dark:border-red-900'" class="px-2 py-0.5 text-[9px] font-black uppercase tracking-wider border rounded-none shrink-0">
            {{ docente.estado ? 'ACTIVO' : 'INACTIVO' }}
          </span>
        </div>

        <div class="flex items-center justify-between gap-2">
          <div class="text-[10px] font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500">
            {{ docente.fechaRegistro | date:'dd/MM/yyyy HH:mm' }}
          </div>
          <div class="inline-flex gap-2">
            <button
              (click)="openEditModal(docente)"
              title="Editar Docente"
              class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-none transition-colors duration-300">
              <span class="material-symbols-outlined text-base block">edit</span>
            </button>
            <button
              (click)="toggleEstado(docente)"
              [title]="docente.estado ? 'Desactivar' : 'Activar'"
              [ngClass]="docente.estado ? 'border-red-200 dark:border-red-900/60 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/20' : 'border-emerald-200 dark:border-emerald-900/60 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-950/20'"
              class="p-1.5 border rounded-none transition-colors">
              <span class="material-symbols-outlined text-base block">
                {{ docente.estado ? 'block' : 'check_circle' }}
              </span>
            </button>
          </div>
        </div>
      </div>
    </div>

    <div class="hidden md:block overflow-x-auto">
      <table class="w-full text-left border-collapse text-xs">
        <thead>
          <tr class="border-b border-slate-200 dark:border-slate-800 bg-slate-100/60 dark:bg-slate-800/40 text-slate-700 dark:text-slate-300 font-bold uppercase tracking-wider text-[10px] transition-colors duration-300">
            <th class="p-4">Nombre Completo</th>
            <th class="p-4">Correo Electronico</th>
            <th class="p-4">Telefono</th>
            <th class="p-4">Fecha Registro</th>
            <th class="p-4">Estado</th>
            <th class="p-4 text-right">Acciones</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-slate-100 dark:divide-slate-800">
          <tr *ngIf="filteredDocentes.length === 0">
            <td colspan="6" class="p-12 text-center text-slate-400 dark:text-slate-500">
              <span class="material-symbols-outlined text-4xl mb-2 text-slate-300 dark:text-slate-700">groups</span>
              <p class="font-medium text-xs">No se encontraron docentes registrados.</p>
            </td>
          </tr>

          <tr *ngFor="let docente of paginatedDocentes; trackBy: trackByDocenteId" class="hover:bg-slate-50/50 dark:hover:bg-slate-800/20 transition-colors duration-300">
            <td class="p-4 font-bold text-slate-900 dark:text-white">
              {{ docente.nombres }} {{ docente.apellidos }}
            </td>
            <td class="p-4 text-slate-600 dark:text-slate-400">
              {{ docente.correo }}
            </td>
            <td class="p-4 text-slate-600 dark:text-slate-400">
              {{ docente.telefono || 'No registrado' }}
            </td>
            <td class="p-4 text-slate-600 dark:text-slate-400">
              {{ docente.fechaRegistro | date:'dd/MM/yyyy HH:mm' }}
            </td>
            <td class="p-4">
              <span [ngClass]="docente.estado ? 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900' : 'bg-red-50 text-red-700 border-red-200 dark:bg-red-950/30 dark:text-red-400 dark:border-red-900'" class="px-2.5 py-1 text-[9px] font-black uppercase tracking-wider border rounded-none">
                {{ docente.estado ? 'ACTIVO' : 'INACTIVO' }}
              </span>
            </td>
            <td class="p-4 text-right">
              <div class="inline-flex gap-2">
                <button
                  (click)="openEditModal(docente)"
                  title="Editar Docente"
                  class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-400 dark:hover:border-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400 rounded-none transition-colors duration-300">
                  <span class="material-symbols-outlined text-base block">edit</span>
                </button>
                <button
                  (click)="toggleEstado(docente)"
                  [title]="docente.estado ? 'Desactivar' : 'Activar'"
                  [ngClass]="docente.estado ? 'border-red-200 dark:border-red-900/60 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/20' : 'border-emerald-200 dark:border-emerald-900/60 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-950/20'"
                  class="p-1.5 border rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">
                    {{ docente.estado ? 'block' : 'check_circle' }}
                  </span>
                </button>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>

    <div *ngIf="totalPages > 1" class="px-4 py-4 border-t border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between transition-colors duration-300">
      <div class="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
        Pagina {{ currentPage }} de {{ totalPages }}
      </div>

      <div class="flex items-center gap-2 flex-wrap">
        <button
          type="button"
          (click)="previousPage()"
          [disabled]="currentPage === 1"
          class="px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-[10px] uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors disabled:opacity-40 disabled:cursor-not-allowed rounded-none">
          Anterior
        </button>

        <button
          *ngFor="let page of [].constructor(totalPages); let i = index"
          type="button"
          (click)="goToPage(i + 1)"
          [ngClass]="currentPage === (i + 1) ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 border-slate-900 dark:border-slate-100' : 'bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 border-slate-300 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700'"
          class="w-10 h-10 border font-black text-[10px] uppercase tracking-widest transition-colors rounded-none">
          {{ i + 1 }}
        </button>

        <button
          type="button"
          (click)="nextPage()"
          [disabled]="currentPage === totalPages"
          class="px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-[10px] uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors disabled:opacity-40 disabled:cursor-not-allowed rounded-none">
          Siguiente
        </button>
      </div>
    </div>
  </div>

  <div *ngIf="showCreateEditModal" role="dialog" aria-modal="true" class="fixed inset-0 bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4" (click)="closeCreateEditModal()">
    <div class="w-full max-w-lg mx-4 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-2xl rounded-none overflow-y-auto relative max-h-[95vh] transition-colors duration-300" (click)="$event.stopPropagation()">
      <div class="px-4 md:px-6 py-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 flex items-center justify-between sticky top-0 z-10 transition-colors duration-300">
        <h3 class="text-sm font-black text-slate-900 dark:text-white uppercase tracking-wider">
          {{ isEditMode ? 'Editar Datos del Docente' : 'Registrar Nuevo Docente' }}
        </h3>
        <button (click)="closeCreateEditModal()" class="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 flex transition-colors">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <form [formGroup]="docenteForm" (ngSubmit)="onSubmit()" class="p-4 md:p-6 space-y-4">
        <div *ngIf="modalErrorMsg" class="flex items-start gap-2 bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900 text-red-800 dark:text-red-300 p-3 rounded-none text-[11px] font-semibold transition-colors duration-300">
          <span class="material-symbols-outlined text-red-600 text-base">warning</span>
          <span>{{ modalErrorMsg }}</span>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Nombres *</label>
            <input formControlName="nombres" type="text" class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
            <p *ngIf="docenteForm.get('nombres')?.hasError('required') && docenteForm.get('nombres')?.touched" class="text-[10px] text-red-600 mt-1">El nombre es requerido.</p>
            <p *ngIf="docenteForm.get('nombres')?.hasError('minlength') && docenteForm.get('nombres')?.touched" class="text-[10px] text-red-600 mt-1">Debe tener al menos 2 caracteres.</p>
          </div>

          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Apellidos *</label>
            <input formControlName="apellidos" type="text" class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
            <p *ngIf="docenteForm.get('apellidos')?.hasError('required') && docenteForm.get('apellidos')?.touched" class="text-[10px] text-red-600 mt-1">El apellido es requerido.</p>
            <p *ngIf="docenteForm.get('apellidos')?.hasError('minlength') && docenteForm.get('apellidos')?.touched" class="text-[10px] text-red-600 mt-1">Debe tener al menos 2 caracteres.</p>
          </div>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Correo Electronico *</label>
            <input formControlName="correo" type="email" class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
            <p *ngIf="docenteForm.get('correo')?.hasError('required') && docenteForm.get('correo')?.touched" class="text-[10px] text-red-600 mt-1">El correo es requerido.</p>
            <p *ngIf="docenteForm.get('correo')?.hasError('email') && docenteForm.get('correo')?.touched" class="text-[10px] text-red-600 mt-1">Ingresa un correo valido.</p>
          </div>

          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Telefono</label>
            <input formControlName="telefono" type="text" class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300" placeholder="Ej. 999999999">
          </div>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">
              Contrasena {{ isEditMode ? '(opcional)' : '*' }}
            </label>
            <input formControlName="password" type="password" class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300" placeholder="Minimo 6 caracteres">
            <p *ngIf="docenteForm.get('password')?.hasError('minlength') && docenteForm.get('password')?.touched" class="text-[10px] text-red-600 mt-1">Minimo 6 caracteres.</p>
            <p class="text-[10px] text-slate-500 dark:text-slate-400 mt-1">
              {{ isEditMode ? 'Dejala vacia si no deseas cambiarla.' : 'Si no la defines, se usara Docente123! por defecto.' }}
            </p>
          </div>

          <div>
            <label class="block text-[10px] font-bold text-slate-700 dark:text-slate-300 mb-1 uppercase tracking-widest">Estado</label>
            <select formControlName="estado" class="w-full px-3 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary transition-colors duration-300">
              <option [ngValue]="true">ACTIVO</option>
              <option [ngValue]="false">INACTIVO</option>
            </select>
          </div>
        </div>

        <div class="pt-4 border-t border-slate-100 dark:border-slate-800 flex flex-col-reverse gap-2 sm:flex-row sm:justify-end sm:gap-3">
          <button type="button" (click)="closeCreateEditModal()" class="px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-xs uppercase tracking-widest hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors rounded-none w-full sm:w-auto">
            Cancelar
          </button>
          <button type="submit" [disabled]="docenteForm.invalid || isFormSubmitting" class="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none disabled:opacity-55 w-full sm:w-auto">
            {{ isFormSubmitting ? 'Guardando...' : 'Guardar Docente' }}
          </button>
        </div>
      </form>
    </div>
  </div>

  <app-confirm-modal
    [visible]="showConfirmModal"
    [type]="confirmModalType"
    [title]="confirmModalTitle"
    [message]="confirmModalMessage"
    confirmText="Confirmar"
    (onConfirm)="confirmAction()"
    (onCancel)="showConfirmModal = false">
  </app-confirm-modal>
</div>
